import React, { useState } from 'react';

function ConvoyView() {
  const [proposals, setProposals] = useState([
    { id: 1, name: 'Stora Sjöfallet (Fricamping)', weather: '☀️ 18°C', votesUp: 3, votesDown: 0 },
    { id: 2, name: 'Trollskogens Camping', weather: '🌧️ 12°C', votesUp: 1, votesDown: 2 }
  ]);

  const handleVote = (id, type) => {
    setProposals(proposals.map(p => {
      if (p.id === id) {
        return { ...p, [type === 'up' ? 'votesUp' : 'votesDown']: p[type === 'up' ? 'votesUp' : 'votesDown'] + 1 };
      }
      return p;
    }));
  };

  return (
    <div style={{ padding: '20px' }} className="animate-fade-in">
      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <h1 style={{ fontSize: '24px', fontWeight: 'bold', color: '#2D5A27', margin: 0 }}>Min Konvoj 🫂</h1>
        <div style={{ backgroundColor: '#E8F5E9', padding: '5px 10px', borderRadius: '20px', color: '#2D5A27', fontSize: '12px', fontWeight: 'bold' }}>
          4 Medlemmar
        </div>
      </header>

      <div style={{ backgroundColor: '#DCEBDE', height: '180px', borderRadius: '20px', display: 'flex', justifyContent: 'center', alignItems: 'center', marginBottom: '20px', boxShadow: 'inset 0 2px 10px rgba(0,0,0,0.05)' }}>
        <div style={{ textAlign: 'center', color: '#2D5A27' }}>
          <span style={{ fontSize: '30px', display: 'block', marginBottom: '10px' }}>🗺️</span>
          <span style={{ fontWeight: 'bold' }}>Live-karta kommer här</span>
        </div>
      </div>

      <h2 style={{ fontSize: '18px', marginBottom: '15px' }}>Omröstning: Nattplats</h2>
      <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
        {proposals.map((prop) => (
          <div key={prop.id} style={{ backgroundColor: '#FFF', padding: '15px', borderRadius: '15px', boxShadow: '0 2px 5px rgba(0,0,0,0.05)' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
              <span style={{ fontWeight: 'bold', fontSize: '16px' }}>{prop.name}</span>
              <span style={{ fontSize: '14px', backgroundColor: '#F5F2ED', padding: '4px 8px', borderRadius: '10px' }}>{prop.weather}</span>
            </div>
            <div style={{ display: 'flex', gap: '10px' }}>
              <button onClick={() => handleVote(prop.id, 'up')} style={voteBtnStyle(true)}>👍 {prop.votesUp}</button>
              <button onClick={() => handleVote(prop.id, 'down')} style={voteBtnStyle(false)}>👎 {prop.votesDown}</button>
            </div>
          </div>
        ))}
      </div>

      <button style={primaryBtnStyle}>+ Lägg till ett förslag</button>
    </div>
  );
}

// Designmallar bara för denna vy
const primaryBtnStyle = { backgroundColor: '#2D5A27', color: 'white', border: 'none', padding: '16px', borderRadius: '15px', fontSize: '16px', fontWeight: 'bold', cursor: 'pointer', width: '100%', marginTop: '20px' };
const voteBtnStyle = (isUpvote) => ({ flex: 1, padding: '10px', border: 'none', borderRadius: '10px', backgroundColor: isUpvote ? '#E8F5E9' : '#FFEBEE', color: isUpvote ? '#2D5A27' : '#C62828', fontWeight: 'bold', cursor: 'pointer', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '5px' });

export default ConvoyView;
